import { db } from "./firebase";
import { ref, get, set, child, serverTimestamp } from "firebase/database";
import { AppUser } from "@/types";
import { User } from "firebase/auth";

export const createUserProfile = async (user: User) => {
    if (!user) return;

    const dbRef = ref(db);
    const userRef = child(dbRef, `users/${user.uid}`);

    try {
        const snapshot = await get(userRef);

        if (!snapshot.exists()) {
            const newUser: Omit<AppUser, 'createdAt'> & { createdAt: any } = {
                uid: user.uid,
                email: user.email || "",
                displayName: user.displayName || "User",
                photoURL: user.photoURL || "",
                role: 'REQUESTER', // Default role
                department: 'General',
                createdAt: new Date().toISOString(), // RTDB stores dates as strings/numbers usually
            };

            await set(ref(db, `users/${user.uid}`), newUser);
        }
    } catch (error) {
        console.error("Error creating user profile", error);
    }
};

export const getUserProfile = async (uid: string): Promise<AppUser | null> => {
    const dbRef = ref(db);
    try {
        const snapshot = await get(child(dbRef, `users/${uid}`));
        if (snapshot.exists()) {
            const data = snapshot.val();
            return {
                ...data,
                createdAt: new Date(data.createdAt)
            } as AppUser;
        }
    } catch (error) {
        console.error("Error fetching user profile", error);
    }
    return null;
};
